fn remove_and_print_even(numbers: &mut Vec<i32>) {
    let mut i = 0;
    while i < numbers.len() {
        let num = numbers[i];
        if num % 2 == 0 {
            println!("Found and removing even number: {}", num);
            // swap_remove is efficient when the order of remaining elements doesn't matter.
            numbers.swap_remove(i);
            // Do not increment i because the element that was at i+1 has now been moved to i.
        } else {
            i += 1;
        }
    }
}

fn main() {
    let mut numbers = vec![10, 20, 30, 40];
    println!("Original list: {:?}", numbers);

    // This call requires a mutable borrow for the duration of the function.
    remove_and_print_even(&mut numbers);

    println!("Final list after processing: {:?}", numbers);
}

